import{_ as t,o as a,c as i,a3 as n}from"./chunks/framework.LBeL10WQ.js";const p=JSON.parse('{"title":"1. Création & Design","description":"","frontmatter":{"title":"1. Création & Design"},"headers":[],"relativePath":"publishers/dedicated-email/1-design.md","filePath":"publishers/dedicated-email/1-design.md"}'),r={name:"publishers/dedicated-email/1-design.md"};function o(s,e,l,d,c,u){return a(),i("div",null,[...e[0]||(e[0]=[n('<h1 id="etape-1-conception-de-l-email" tabindex="-1">Étape 1 : Conception de l&#39;Email <a class="header-anchor" href="#etape-1-conception-de-l-email" aria-label="Permalink to &quot;Étape 1 : Conception de l&#39;Email&quot;">​</a></h1><p>Une fois notifié d&#39;une nouvelle campagne, vous concevez l&#39;email. L&#39;annonceur fournit le fond (l&#39;offre), vous apportez la forme (le ton).</p><hr><h2 id="acceder-au-brief" tabindex="-1">Accéder au Brief <a class="header-anchor" href="#acceder-au-brief" aria-label="Permalink to &quot;Accéder au Brief&quot;">​</a></h2><p>Connectez-vous sur <a href="https://app.getinside.media/" target="_blank" rel="noreferrer">app.getinside.media</a> → onglet <strong>&quot;Campagnes&quot;</strong> → sélectionnez la campagne active. Vous y trouverez :</p><ul><li>L&#39;offre commerciale et les arguments clés</li><li>Les visuels produits (logos, packshots HD)</li><li>Les liens de redirection de l&#39;annonceur</li></ul><hr><h2 id="strategie-de-co-branding" tabindex="-1">Stratégie de Co-branding <a class="header-anchor" href="#strategie-de-co-branding" aria-label="Permalink to &quot;Stratégie de Co-branding&quot;">​</a></h2><p>L&#39;objectif est l&#39;<strong>endorsement natif</strong> : le message doit être perçu comme une recommandation sincère de votre part, pas comme une publicité externe.</p><div class="gi-value-grid"><div class="gi-value-card"><strong>✅ À FAIRE — Endorsement</strong><p>Vos abonnés doivent sentir que le message vient de vous.</p><ul><li><strong>Header :</strong> Utilisez votre en-tête habituel.</li><li><strong>Édito :</strong> Rédigez une intro — <em>&quot;Chers clients, voici un coup de cœur…&quot;</em></li><li><strong>Design :</strong> Intégrez les visuels de l&#39;annonceur mais gardez vos polices et boutons.</li></ul></div><div class="gi-value-card"><strong>❌ À ÉVITER — Pub Brute</strong><p>Ne transformez pas votre newsletter en panneau publicitaire.</p><ul><li>Ne copiez-collez pas un HTML fourni par la marque.</li><li>Ne supprimez pas votre logo.</li><li>Si l&#39;email ne vous ressemble pas, votre audience se désabonnera.</li></ul></div></div><hr><h2 id="exemples-de-campagnes" tabindex="-1">Exemples de campagnes <a class="header-anchor" href="#exemples-de-campagnes" aria-label="Permalink to &quot;Exemples de campagnes&quot;">​</a></h2><p>Des rendus réels en ligne (responsive, co-branding, endorsement) :</p><table tabindex="0"><thead><tr><th style="text-align:left;">Campagne</th><th style="text-align:left;">Contexte</th><th style="text-align:left;">Rendu</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>Caats × Les Petits Culottés</strong></td><td style="text-align:left;">Petfood — audience Parents/Famille</td><td style="text-align:left;"><a href="https://benoit-prentout.github.io/archive-news/fb0907efa715/index.html" target="_blank">Voir</a></td></tr><tr><td style="text-align:left;"><strong>HelloFresh × Berceau Magique</strong></td><td style="text-align:left;">Box repas — cible Jeunes Parents</td><td style="text-align:left;"><a href="https://benoit-prentout.github.io/archive-news/71541edf985d/index.html" target="_blank">Voir</a></td></tr><tr><td style="text-align:left;"><strong>Les Petits Frères des Pauvres</strong></td><td style="text-align:left;">Caritatif — collecte de fonds</td><td style="text-align:left;"><a href="https://benoit-prentout.github.io/archive-news/3adf10561e05/index.html" target="_blank">Voir</a></td></tr></tbody></table><hr><h2 id="option-—-delegation-studio" tabindex="-1">Option — Délégation Studio <a class="header-anchor" href="#option-—-delegation-studio" aria-label="Permalink to &quot;Option — Délégation Studio&quot;">​</a></h2><div class="info custom-block"><p class="custom-block-title">Pas le temps de créer ?</p><p>Déléguez au <strong>Studio getinside</strong> : création de l&#39;email à vos couleurs, rédaction de l&#39;édito et intégration technique.</p><p><strong>550€ HT</strong> par campagne (déduit de vos revenus) → <a href="mailto:studio@getinside.fr" target="_blank" rel="noreferrer">studio@getinside.fr</a></p></div><hr><p>→ <a href="./2-tracking-sending.html">Étape 2 : Tracking &amp; Envoi</a></p>',19)])])}const m=t(r,[["render",o]]);export{p as __pageData,m as default};
